// ─── Dados brutos ───────────────────────────────────────────────────────────
const webhookData = $('Recebe Mensagem do Backend').item.json.body;
const agentsRaw   = $('Busca Agente da Instância').item.json;
const historyRaw  = $('Busca Histórico da Conversa').item.json;
const leadRaw     = $('Busca Dados do Lead').item.json;

// ─── Agente ativo ───────────────────────────────────────────────────────────
const agent = Array.isArray(agentsRaw)
  ? (agentsRaw.find(a => a.status === 'ACTIVE') || agentsRaw[0])
  : agentsRaw;

if (!agent) throw new Error('Nenhum agente encontrado para esta instância');

const historyLimit  = agent.historyLimit  || 10;
const temperature   = agent.temperature   ?? 0.7;
const model         = agent.aiModel       || 'openai/gpt-4o-mini';

// ─── Dados do lead (memória de longo prazo) ──────────────────────────────────
const lead = leadRaw && !leadRaw.error ? leadRaw : null;
const leadName  = lead?.name  || webhookData.pushName || 'Usuário';
const leadEmail = lead?.email || null;
const leadNotes = lead?.notes || null;
const leadScore = lead?.score ?? null;
const leadStatus = lead?.status || null;

// ─── System prompt enriquecido ───────────────────────────────────────────────
let systemContent = agent.systemPrompt || agent.instructions || '';

// Bloco de contexto do contato (injetado automaticamente)
let contactContext = `\n\n---\n## Contexto do Contato\n`;
contactContext += `- **Nome**: ${leadName}\n`;
if (leadEmail)  contactContext += `- **Email**: ${leadEmail}\n`;
if (leadStatus) contactContext += `- **Status**: ${leadStatus}\n`;
if (leadScore !== null) contactContext += `- **Score**: ${leadScore}\n`;
if (leadNotes)  contactContext += `\n### Memória / Notas sobre este contato:\n${leadNotes}\n`;
contactContext += `---`;

systemContent += contactContext;

// Guardrails (limites e restrições do agente)
if (agent.guardrails) {
  systemContent += `\n\n## Diretrizes e Restrições\n${agent.guardrails}`;
}

// Configurações de resposta
systemContent += `\n\n## Configurações de Resposta\n- Idioma: ${agent.language || 'pt-BR'}\n- Tom: ${agent.tone || 'amigável'}\n- Responda de forma natural, sem markdown excessivo, como em uma conversa de WhatsApp.`;

// ─── Histórico da conversa ───────────────────────────────────────────────────
const historyMessages = [];
if (Array.isArray(historyRaw)) {
  // Pega as últimas N mensagens excluindo a atual
  const previous = historyRaw.slice(-(historyLimit + 1), -1);
  for (const msg of previous) {
    historyMessages.push({
      role: msg.direction === 'INBOUND' ? 'user' : 'assistant',
      content: msg.content
    });
  }
}

// ─── Array final de mensagens para o LLM ────────────────────────────────────
const messages = [
  { role: 'system', content: systemContent },
  ...historyMessages,
  { role: 'user',   content: webhookData.content }
];

return [{
  json: {
    messages,
    model,
    temperature,
    agentId:        agent.id,
    agentName:      agent.name,
    instanceName:   webhookData.instanceName,
    phoneNumber:    webhookData.phoneNumber,
    conversationId: webhookData.conversationId,
    instanceId:     webhookData.instanceId
  }
}];

// Adiciona instruções de qualificação ao systemContent do item anterior
const item = $input.item.json;

const qualificationInstructions = `

## Sistema de Qualificação de Leads (INTERNO — nunca mostre ao usuário)
Você deve analisar silenciosamente a conversa e emitir sinais de qualificação no FINAL de cada resposta sua, APÓS o texto visível ao usuário.
Os sinais são invisíveis para o cliente — serão removidos antes do envio.

Formato dos sinais: <<IA_LEAD:TIPO:VALOR>>

Tipos disponíveis:
- SCORE: Ajuste de pontuação (ex: <<IA_LEAD:SCORE:+15>>, <<IA_LEAD:SCORE:+30>>)
- STATUS: Mudança de status (<<IA_LEAD:STATUS:QUALIFIED>>, <<IA_LEAD:STATUS:CONVERTED>>, <<IA_LEAD:STATUS:DISQUALIFIED>>)
- NOTE: Nota sobre o lead (<<IA_LEAD:NOTE:cliente perguntou sobre plano premium>>)

Regras de pontuação:
- Lead respondeu e demonstrou interesse: +10
- Lead perguntou sobre preço/planos: +15
- Lead pediu mais detalhes sobre o produto: +15
- Lead demonstrou intenção clara de compra: +25
- Lead pediu para fechar negócio/comprar: +30
- Lead demonstrou desinteresse: -10

Regras de status:
- Emita STATUS:QUALIFIED quando score total indicar interesse genuíno e lead deu informações de contato ou demonstrou intenção
- Emita STATUS:CONVERTED quando lead confirmou compra/contratação
- Emita STATUS:DISQUALIFIED quando lead explicitamente recusou ou é spam

Sempre emita pelo menos um sinal NOTE por conversa para registrar informações relevantes.
Não emita mais de 3 sinais por resposta. Só emita sinais quando relevante.`;

// Injeta após o system message
const messages = item.messages || [];
if (messages.length > 0 && messages[0].role === 'system') {
  messages[0].content = messages[0].content + qualificationInstructions;
}

return [{ json: { ...item, messages } }];

const openrouterResponse = $input.item.json;
const prevData = $('Injeta Instruções de Qualificação').item.json;

const rawResponse = openrouterResponse.choices?.[0]?.message?.content || '';

if (!rawResponse) throw new Error('IA retornou resposta vazia');

// ─── Extrai sinais de qualificação ──────────────────────────────────────────
const signalRegex = /<<IA_LEAD:([^>]+)>>/g;
const signals = [];
let match;
while ((match = signalRegex.exec(rawResponse)) !== null) {
  signals.push(match[1]);
}

// Remove os sinais da resposta antes de enviar ao usuário
const aiResponse = rawResponse.replace(/<<IA_LEAD:[^>]+>>/g, '').trim();

// Recupera o leadId do webhook original
const webhookData = $('Recebe Mensagem do Backend').item.json.body;

return [{
  json: {
    aiResponse,
    signals,
    leadId:         webhookData.leadId,
    instanceName:   prevData.instanceName,
    phoneNumber:    prevData.phoneNumber,
    conversationId: prevData.conversationId,
    instanceId:     prevData.instanceId
  }
}];
